import { createRouter, createWebHistory, RouteRecordRaw } from "vue-router";
import store from "@/store";
import { onAuthStateChanged, getAuth } from "@firebase/auth";
import { app } from "@/firebase";

const routes: Array<RouteRecordRaw> = [
  {
    path: "/",
    name: "home",
    meta: {
      requireAuth: false,
    },
    component: () => import("../views/HomePage.vue"),
  },
  {
    path: "/login",
    name: "login",
    meta: {
      requireAuth: false,
    },
    component: () =>
      import(/* webpackChunkName: "login" */ "../views/LoginPage.vue"),
  },
  {
    path: "/dashboard",
    name: "dashboard",
    meta: {
      requireAuth: true,
    },
    component: () =>
      import(/* webpackChunkName: "dashboard" */ "../views/DashboardPage.vue"),
  },
  {
    path: "/profile",
    name: "profile",
    meta: {
      requireAuth: true,
    },
    component: () =>
      import(/* webpackChunkName: "profile" */ "../views/ProfilePage.vue"),
  },
  {
    path: "/fuel",
    name: "fuel",
    meta: {
      requireAuth: true,
    },
    component: () => import("../views/FuelTrackingPage.vue"),
  },
  {
    path: "/todo",
    name: "todo",
    meta: {
      requireAuth: true,
    },
    component: () => import("../views/ToDoPage.vue"),
  },
];

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes,
  linkExactActiveClass: "active",
});

const auth = getAuth();
onAuthStateChanged(auth, (_user) => {
  router.beforeEach((to, from, next) => {
    console.log("user", getAuth(app));
    if (to.meta.requireAuth && _user != null) {
      return next();
    } else if (to.meta.requireAuth && _user == null) {
      return next("/login");
    } else {
      return next();
    }
  });
  store.commit("setUser", _user);
  // if (_user == null) {
  //   router.push("/login");
  // }
});

export default router;
