import { FuelDataType } from "@/core/types/fuel_data_type";
import { createStore } from "vuex";
import { TodoType } from "../core/types/todo_dtype";
import { getAuth } from "@firebase/auth";
import { app } from "../firebase/index";

export default createStore({
  state: () => ({
    data: Array<FuelDataType>(),
    user: false,
    todos: Array<TodoType>(),
  }),
  mutations: {
    setData(state, data) {
      state.data = data;
    },
    setTodo(state, data) {
      state.todos = data;
    },
    setUser(state, user) {
      state.user = user;
    },
  },
  getters: {
    getData(state) {
      return state.data;
    },
    getUser(state) {
      return state.user;
    },
    getTodos(state): TodoType[] {
      return state.todos;
    },
  },
  actions: {},
  modules: {},
});
